/**
 * =====================
 */
/**
 * GLOBALS
 */
/**
 * =====================
 */
// =====================
// SPAWN VASES (USING vpot)
// =====================
function spawnVases () {
    locations = tiles.getTilesByType(assets.tile`baseTransparency16`)
    while (placed < 3 && attempts < 50) {
        tile = locations[randint(0, locations.length - 1)]
        dx = Math.abs(tile.col - heroTile.col)
        dy = Math.abs(tile.row - heroTile.row)
        // at least 4 tiles away
        if (dx + dy >= 4) {
            // ✅ CORRECT asset name: vpot
            vase = sprites.create(assets.image`vpot`, SpriteKind.Food)
            tiles.placeOnTile(vase, tile)
            placed += 1
        }
        attempts += 1
    }
}
// =====================
// BREAK VASE
// =====================
sprites.onOverlap(SpriteKind.Player, SpriteKind.Food, function (player2, vase) {
    roll = randint(1, 100)
    if (roll <= 50) {
        health += 1
        game.showLongText("You gained health!", DialogLayout.Bottom)
    } else if (roll <= 95) {
        health += 0 - 1
        game.showLongText("You lost health!", DialogLayout.Bottom)
    } else {
        keyFound = true
        game.showLongText("You found the key!", DialogLayout.Center)
        spawnChest()
    }
    info.setScore(health)
    if (health <= 0) {
        game.over(false)
    }
    vase.destroy()
})
// =====================
// CHEST
// =====================
function spawnChest () {
    chest = sprites.create(assets.image`chest`, SpriteKind.Projectile)
    locations2 = tiles.getTilesByType(assets.tile`baseTransparency16`)
    tile2 = locations2[randint(0, locations2.length - 1)]
    tiles.placeOnTile(chest, tile2)
}
// =====================
// WIN CONDITION
// =====================
sprites.onOverlap(SpriteKind.Player, SpriteKind.Projectile, function (player2, chest) {
    if (keyFound) {
        game.showLongText("Level Complete!", DialogLayout.Center)
        game.over(true)
    }
})
let tile2: tiles.Location = null
let locations2: tiles.Location[] = []
let chest: Sprite = null
let keyFound = false
let roll = 0
let vase: Sprite = null
let dy = 0
let dx = 0
let tile: tiles.Location = null
let attempts = 0
let placed = 0
let locations: tiles.Location[] = []
let heroTile: tiles.Location = null
let health = 0
health = 3
// =====================
// TILEMAP
// =====================
tiles.setTilemap(tilemap`F1`)
// =====================
// PLAYER (CENTER SPAWN)
// =====================
let hero = sprites.create(assets.image`hero`, SpriteKind.Player)
let allTiles = tiles.getTilesByType(assets.tile`baseTransparency16`)
let centerIndex = Math.floor(allTiles.length / 2)
heroTile = allTiles[centerIndex]
tiles.placeOnTile(hero, heroTile)
// camera follows hero
scene.cameraFollowSprite(hero)
controller.moveSprite(hero)
info.setScore(health)
// =====================
// START
// =====================
spawnVases()

